svg.script:
  const SOURCE_URL = 'https://cdn.jsdelivr.net/gh/fidgetsetc/birdmath@main/singlefile.html'; const statusText = document.getElementById('status'); const wrapper = document.getElementById('wrapper'); const frame = document.getElementById('app-frame');
async function injectBirdmath() {
  try {
    // Fetch the raw HTML
    const response = await fetch(SOURCE_URL);
    if (!response.ok) throw new Error(&#39;Fetch failed&#39;);
    const htmlContent = await response.text();

    // Create the Blob
    const blob = new Blob([htmlContent], { type: &#39;text/html&#39; });
    const blobUrl = URL.createObjectURL(blob);

    // Put it in the frame and show it
    frame.src = blobUrl;

    frame.onload = () =&gt; {
      statusText.setAttribute(&#39;visibility&#39;, &#39;hidden&#39;);
      wrapper.setAttribute(&#39;visibility&#39;, &#39;visible&#39;);
    };
  } catch (err) {
    statusText.textContent = &quot;L + RATIO + ERROR: &quot; + err.message;
    statusText.setAttribute(&#39;fill&#39;, &#39;red&#39;);
  }
}

// Execute
injectBirdmath();
]]&gt;

</script>
</svg>
